using Forge.Core.Entities;
using Forge.Core.Enums;
using Forge.Data.Context;

using Serilog;

namespace Forge.Api.Data.TrainingContent;

public class EstimatesTraining : TrainingContentBase
{
    public EstimatesTraining(AppDbContext db, Dictionary<string, int> slugMap) : base(db, slugMap) { }

    public override async Task SeedAsync()
    {
        // ── Overview (Article) ───────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Estimates Overview",
            Slug = "estimates-overview",
            Summary = "What estimates are, how they differ from quotes, their non-binding nature, and how to convert them into formal quotes.",
            ContentType = TrainingContentType.Article,
            EstimatedMinutes = 4,
            IsPublished = true,
            SortOrder = 1,
            AppRoutes = """["/customers"]""",
            Tags = """["estimates","customers"]""",
            ContentJson = """{"body":"## Estimates Overview\n\nEstimates are lightweight pricing documents you give customers early in a conversation, before a formal quote. They give a cost picture without the ceremony of a binding quote. Estimates live on the customer's Estimates tab — each one belongs to a specific customer.\n\n### Estimates vs Quotes\n\nEstimates and quotes serve different purposes in the sales process:\n\n- **Estimate** — Starts from a single ballpark amount with a title and an optional description, and you can break it into lines afterward. It has no tax, no shipping address, and doesn't turn into an order on its own.\n- **Quote** — A binding, fixed-price commitment with individual lines (part, quantity, unit price), a tax rate, and a formal lifecycle. A quote can become a Sales Order.\n\nThe fast path stays simple: when a customer calls and asks 'how much to make 500 of these?', create an estimate with just a title and an amount in seconds. When you want to break that number down, reopen the estimate and add lines.\n\n### Line Items on an Estimate\n\nEstimates support lines, but you add them to a **saved** estimate — not while first creating it. Save the header first:\n\n1. Create the estimate with a title and an estimated amount (and optionally a description, valid-until date, and notes).\n2. Reopen it by clicking its row — a **Lines** section appears below the form.\n3. Click **Add Line** to itemize. Each line can be a **catalog part** (pick it and the description fills in for you) or a **lump-sum** line (leave the part empty and type a description). Set a quantity and a price for each.\n\nAs you add, edit, or delete lines, the estimate's **total follows the sum of the lines** — the header amount and the lines stay in agreement. A line with no part shows 'Lump sum' in the Part column.\n\nYou can edit lines only while the estimate is a **draft**. Once it's Sent, Accepted, or converted to a quote, the lines become view-only.\n\n### The Estimate Lifecycle\n\nEvery estimate starts as a **Draft** and moves through a simple lifecycle:\n\n1. **Draft** — Just created, still being refined. You can freely edit the title, amount, description, notes, and lines.\n2. **Sent** — You've shared the estimate with the customer, by email, PDF, or verbally. The header fields stay editable; the lines become view-only.\n3. **Accepted** — The customer agreed to move forward based on the estimate.\n4. **Declined** — The customer decided not to proceed.\n5. **Expired** — The estimate passed its Valid Until date without a decision.\n6. **Converted to Quote** — The estimate became a formal quote. The estimate is kept, with a link to that quote.\n\n### Converting to a Quote\n\nWhen a customer accepts an estimate and wants to move forward, you convert it to a formal quote. Click the forward-arrow on the estimate row and confirm. This:\n\n- Creates a new draft quote with its own quote number\n- Brings over the customer and the estimate's lines\n- Marks the estimate Converted to Quote\n- Records when the conversion happened\n- Links the new quote back to the estimate it came from\n\nFrom there you set the pricing, add the tax rate, and run the normal quote lifecycle on the Quotes page.\n\n### When to Use Estimates\n\n- When a customer asks for a rough cost before you've done detailed engineering\n- When you want to qualify a lead before investing time in a full quote\n- When you need pricing fast (a header-only estimate takes seconds to create)\n- When you want to show a customer a simple line breakdown without committing to a binding quote\n\n### Where to Find Estimates\n\nEstimates live on the customer's detail page. Go to Customers, pick a customer, then open the Estimates tab. All of that customer's estimates are listed there, and you can sort and filter them. You can create, edit (including lines), convert, and delete estimates right from this tab.","sections":[]}"""
        });

        // ── Walkthrough ──────────────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Estimates — Guided Tour",
            Slug = "estimates-walkthrough",
            Summary = "A guided tour of creating and managing estimates via the customer detail Estimates tab.",
            ContentType = TrainingContentType.Walkthrough,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 2,
            AppRoutes = """["/customers"]""",
            Tags = """["estimates","customers","walkthrough"]""",
            ContentJson = """{"appRoute":"/customers","startButtonLabel":"Tour Estimates","steps":[{"element":"app-data-table","popover":{"title":"Customer List","description":"Start by picking a customer. Click any row to open that customer, where you manage their estimates, quotes, and orders.","side":"top"}},{"element":"[data-testid='new-customer-btn']","popover":{"title":"Create Customer","description":"Estimates always belong to a customer. Click here to add one first.","side":"bottom"}},{"element":".filters-bar app-input","popover":{"title":"Search Customers","description":"Find a customer fast. Search by name, company, email, or phone, then click their row to open them and go to the Estimates tab.","side":"bottom"}},{"element":"app-data-table","popover":{"title":"Create and Itemize an Estimate","description":"Open a customer's Estimates tab to work with estimates. Click 'New Estimate', type a title and a ballpark amount, and save. To break that number down, reopen the estimate — a Lines section appears. Click 'Add Line' to add a catalog part or a free-text line, then set a quantity and price. The total keeps itself in step with the lines. You can edit lines while the estimate is still a draft.","side":"top"}},{"element":"app-data-table","popover":{"title":"Convert to a Quote","description":"Open the estimate to turn it into a quote. When the customer is ready, click the forward-arrow on the estimate row and confirm. This starts a draft quote that brings over the customer and the lines. You then set pricing and the tax rate on the Quotes page.","side":"top"}}]}"""
        });

        // ── Field Reference (QuickRef) ───────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Estimates Field Reference",
            Slug = "estimates-field-reference",
            Summary = "Complete reference for every field, status, action, and validation rule in the Estimates feature.",
            ContentType = TrainingContentType.QuickRef,
            EstimatedMinutes = 3,
            IsPublished = true,
            SortOrder = 3,
            AppRoutes = """["/customers"]""",
            Tags = """["estimates","customers","reference"]""",
            ContentJson = """{"title":"Estimates Field Reference","groups":[{"heading":"Estimate Form Fields","items":[{"label":"Title (required)","value":"A short name for the estimate, up to 300 characters. For example 'CNC Bracket Prototype — 500 pcs'. Can't be left blank."},{"label":"Description","value":"Optional, up to 2000 characters. A fuller explanation of what the estimate covers — assumptions, scope, and exclusions."},{"label":"Estimated Amount (required)","value":"The ballpark dollar figure. Must be zero or more. Once you add lines, this amount follows the sum of the lines."},{"label":"Valid Until","value":"Optional expiration date. After this date the estimate is treated as expired if the customer hasn't replied."},{"label":"Status (edit only)","value":"Shown only when editing an existing estimate. Choose Draft, Sent, Accepted, Declined, or Expired. New estimates start as Draft. Converted to Quote is set for you when you convert."},{"label":"Notes","value":"Optional, up to 2000 characters. Internal notes — assumptions, material considerations, and follow-up reminders."}]},{"heading":"Estimate Statuses","items":[{"label":"Draft (gray label)","value":"The starting status. The estimate is still being prepared and can be fully edited."},{"label":"Sent (blue label)","value":"You've shared the estimate with the customer. Still editable."},{"label":"Accepted (green label)","value":"The customer agreed to proceed based on this ballpark figure."},{"label":"Declined (red label)","value":"The customer decided not to proceed."},{"label":"Expired (amber label)","value":"The estimate passed its Valid Until date without a customer decision."},{"label":"Converted to Quote (teal label)","value":"The estimate was turned into a formal quote. Set for you when you convert, with a link to that quote."}]},{"heading":"Line Items (saved draft estimate)","items":[{"label":"Where","value":"The Lines section appears when you reopen a saved estimate by clicking its row. It isn't there when you first create one — you save the header first, then add lines."},{"label":"When editable","value":"You can add, edit, and delete lines only while the estimate is a draft. Once it's Sent, Accepted, or converted, the lines are view-only and a note explains why."},{"label":"Add Line button","value":"Opens a small form below the lines table. Unavailable while you're already editing another line."},{"label":"Catalog Part (optional)","value":"Pick a part from your catalog and its description fills in for you. Leave it empty for a lump-sum line — the Part column then shows 'Lump sum'."},{"label":"Description (required)","value":"A free-text description of the line. Required on every line."},{"label":"Qty (required)","value":"How many. Must be at least 0.0001, so fractional amounts are allowed."},{"label":"Amount (required)","value":"The price per unit, zero or more. The line total is quantity times price."},{"label":"Edit (pencil) / Delete (trash)","value":"Edit reopens a line's description, quantity, and price (the part stays the same). Delete removes the line after you confirm."},{"label":"Estimated Amount sync","value":"After you add, edit, or delete a line, the estimate's total updates to the sum of the lines and the list refreshes."}]},{"heading":"Actions","items":[{"label":"New Estimate (main button)","value":"Opens the form to create an estimate — title, description, amount, valid-until date, and notes. Saves as a draft."},{"label":"Row click","value":"Opens the estimate for editing, filled in with its current values. The Status field appears here."},{"label":"Convert to Quote (forward-arrow)","value":"Turns the estimate into a formal draft quote, carrying over the customer and the lines, and marks the estimate Converted to Quote. Set the pricing and tax rate on the Quotes page. Hidden once an estimate has already been converted."},{"label":"Delete (trash icon)","value":"Removes the estimate after you confirm. Shows a warning with the estimate's title first."},{"label":"Save (dialog button)","value":"Creates or updates the estimate. Unavailable while the form has a problem or a save is in progress. A warning icon next to it lists what needs fixing."},{"label":"Cancel (dialog button)","value":"Closes the form without saving."}]},{"heading":"Table Columns","items":[{"label":"Title","value":"The estimate's title. Sortable."},{"label":"Amount","value":"The estimate total, shown as currency such as $12,500.00 and right-aligned. Sortable."},{"label":"Status","value":"A colored label — Draft (gray), Sent (blue), Accepted (green), Declined (red), Expired (amber), or Converted to Quote (teal). Sortable and filterable."},{"label":"Valid Until","value":"The expiration date, shown as MM/dd/yyyy, or blank if none is set. Sortable."},{"label":"Created","value":"When the estimate was first created, shown as MM/dd/yyyy. Sortable."},{"label":"Actions","value":"Holds the Convert to Quote arrow (hidden once converted) and the Delete button."}]},{"heading":"Validation Rules","items":[{"label":"Title","value":"Required, up to 300 characters. Can't be blank."},{"label":"Estimated Amount","value":"Required. Must be a number of zero or more."},{"label":"Description","value":"Optional, up to 2000 characters."},{"label":"Notes","value":"Optional, up to 2000 characters."},{"label":"Valid Until","value":"Optional. You can set a past date if you need to backdate."},{"label":"Convert to Quote","value":"Available only if the estimate hasn't already been converted. Asks you to confirm."},{"label":"Delete","value":"Asks you to confirm. The estimate is hidden, not erased — it's kept for your records."}]},{"heading":"Navigation & Access","items":[{"label":"Location","value":"Customers page, then pick a customer and open the Estimates tab. Every estimate belongs to a single customer."},{"label":"Related features","value":"Quotes (formal, itemized commitments), Sales Orders (created from accepted quotes), and the customer's detail page."},{"label":"Good to know","value":"Estimates and formal quotes are closely related, but an estimate stays lightweight — no tax rate and no direct order conversion of its own."}]}]}"""
        });

        // ── Knowledge Check (Quiz) ───────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Estimates Knowledge Check",
            Slug = "estimates-quiz",
            Summary = "Test your knowledge of the Estimates feature: purpose, lifecycle, conversion to quotes, and field details.",
            ContentType = TrainingContentType.Quiz,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 4,
            AppRoutes = """["/customers"]""",
            Tags = """["estimates","customers","quiz"]""",
            ContentJson = """{"passingScore":80,"questionsPerQuiz":8,"shuffleOptions":true,"showExplanationsAfterSubmit":true,"questions":[{"id":"est1","text":"A customer calls and asks 'roughly how much would 500 aluminum brackets cost?' You don't have detailed engineering yet. What should you create in QB Engineer?","options":[{"id":"a","text":"A Quote with a single line item for 500 brackets"},{"id":"b","text":"A Sales Order with an estimated total"},{"id":"c","text":"An Estimate on the customer's Estimates tab with the ballpark amount","isCorrect":true},{"id":"d","text":"A Job on the Kanban board tagged as 'pricing'"}],"explanation":"Estimates are designed for exactly this scenario — providing a quick, non-binding ballpark figure before you've done detailed engineering. Create one on the customer's Estimates tab with a title and dollar amount."},{"id":"est2","text":"What is the key difference between an estimate and a quote in QB Engineer?","options":[{"id":"a","text":"Estimates require manager approval; quotes do not"},{"id":"b","text":"A quote is a binding commitment that carries a tax rate and can convert to a sales order; an estimate is lighter-weight, has no tax calculation, and can't convert to an order on its own — even though both can be line-itemized","isCorrect":true},{"id":"c","text":"Estimates have no line items at all; only quotes can be itemized"},{"id":"d","text":"Estimates are emailed automatically; quotes must be printed"}],"explanation":"Both documents can be broken into lines. The real difference is commitment and scope: a quote is binding, carries a tax rate, and converts to a sales order; an estimate is lighter-weight, has no tax, and converts to a quote (not directly to an order). The 'estimates have no lines' idea is outdated — estimates support catalog-part and lump-sum lines."},{"id":"est3","text":"Where do you find and manage estimates in QB Engineer?","options":[{"id":"a","text":"On a dedicated Estimates page in the main navigation"},{"id":"b","text":"On the customer detail page, under the Estimates tab","isCorrect":true},{"id":"c","text":"In the Quotes module, filtered by type"},{"id":"d","text":"On the Dashboard under the Sales widget"}],"explanation":"Estimates are accessed through the customer detail page. Navigate to Customers, select a customer, then click the Estimates tab. All estimates for that customer are listed there."},{"id":"est4","text":"You created an estimate last week and the customer just said they want to proceed. What is the next step?","options":[{"id":"a","text":"Change the estimate's status to Accepted, then create a Sales Order manually"},{"id":"b","text":"Delete the estimate and create a Quote from scratch"},{"id":"c","text":"Click the Convert to Quote icon on the estimate row — it creates a new formal quote linked to the estimate","isCorrect":true},{"id":"d","text":"There's no conversion — you re-key the estimate as a brand-new quote by hand"}],"explanation":"Click the forward-arrow on the estimate row to convert it. This creates a new draft quote, brings over the customer and lines, marks the estimate Converted to Quote, and links them together. You then set the pricing on the new quote — you don't re-key it by hand."},{"id":"est5","text":"What happens to an estimate after it is converted to a quote?","options":[{"id":"a","text":"The estimate is deleted and replaced by the quote"},{"id":"b","text":"The estimate's status changes to Converted to Quote, and it links to the new quote. The estimate is kept.","isCorrect":true},{"id":"c","text":"The estimate becomes editable again so you can update the amount"},{"id":"d","text":"The estimate is archived and hidden from the Estimates tab"}],"explanation":"The estimate is kept, its status set to Converted to Quote and the time recorded. It stays linked to the quote it created, and you can still see it in the Estimates tab."},{"id":"est6","text":"Which fields are required when creating a new estimate?","options":[{"id":"a","text":"Title, Description, Estimated Amount, and Valid Until date"},{"id":"b","text":"Title and Estimated Amount only — lines are added afterward on the saved estimate","isCorrect":true},{"id":"c","text":"Title, Estimated Amount, and at least one line"},{"id":"d","text":"Only the Estimated Amount — everything else is optional"}],"explanation":"Creating an estimate needs only two things: a Title (up to 300 characters) and an Estimated Amount (zero or more). Description, Valid Until, and Notes are optional. Lines aren't part of creating it — you save the header first, then add lines when you reopen the estimate, and the total then follows the lines."},{"id":"est7","text":"An estimate shows an amber 'Expired' status label. What does this mean?","options":[{"id":"a","text":"The estimate was rejected by the customer"},{"id":"b","text":"The estimate passed its Valid Until date without a customer decision","isCorrect":true},{"id":"c","text":"The estimate has been converted to a quote"},{"id":"d","text":"The estimate was created more than 30 days ago"}],"explanation":"An amber Expired label means the estimate passed its Valid Until date without the customer accepting or declining. You can still edit it and extend the date if needed."},{"id":"est8","text":"A new quote was created from an estimate conversion. What state does the new quote start in?","options":[{"id":"a","text":"Draft status, carrying over the estimate's customer and lines — you then set pricing and add the tax rate","isCorrect":true},{"id":"b","text":"Sent status, already shared with the customer"},{"id":"c","text":"Accepted status since the customer already agreed to the estimate"},{"id":"d","text":"Draft status with no lines — everything must be re-entered from scratch"}],"explanation":"The converted quote starts as a draft and carries over the estimate's customer and its lines. From there you set the pricing, add the tax rate, and run the normal quote lifecycle. You don't re-enter the lines from scratch — that's the whole point of converting rather than starting a new quote."},{"id":"est9","text":"You want to delete an estimate that was entered by mistake. What happens?","options":[{"id":"a","text":"The estimate is permanently erased"},{"id":"b","text":"The estimate is hidden, not erased — it's kept for your records but no longer shown. A confirmation appears first.","isCorrect":true},{"id":"c","text":"The estimate moves to a Trash folder where it can be restored within 30 days"},{"id":"d","text":"You cannot delete estimates — you can only change their status to Declined"}],"explanation":"Deleting an estimate asks you to confirm first. Once you confirm, the estimate is hidden rather than erased — it's kept for your records but no longer appears in the Estimates tab."},{"id":"est10","text":"Can you convert the same estimate to a quote more than once?","options":[{"id":"a","text":"Yes — each conversion creates an additional quote linked to the same estimate"},{"id":"b","text":"No — once an estimate has been converted, the Convert to Quote button is hidden and a second conversion is blocked","isCorrect":true},{"id":"c","text":"Yes, but only if the first quote it created was deleted"},{"id":"d","text":"No — you must create a new estimate to generate another quote"}],"explanation":"An estimate can only be converted once. The Convert to Quote arrow is hidden for estimates that already have a quote, and a second conversion is blocked — you'd see a message that it has already been converted."}]}"""
        });

        Log.Information("Seeded Estimates training modules");
    }
}
